import boto3

def create_sns_subscription():
    sns_client = boto3.client('sns')
    topic = input("Enter the SNS topic ARN: ")
    
    while True:
        user_provided_url = input("Enter the subscription endpoint URL (or type 'exit' to stop): ")
        if user_provided_url.lower() == 'exit':
            break
        response = sns_client.subscribe(
            TopicArn=topic,
            Protocol='https',
            Endpoint=user_provided_url
        )
        print(f"Subscription ARN: {response['SubscriptionArn']}")

if __name__ == "__main__":
    create_sns_subscription()